import React from "react";

const Header = ({ ready, onMenuOpen }) => {
  return (
    <>
      <header
        className={`
          fixed left-1/2 top-3 sm:top-5 z-[5000]
          flex w-[95%] max-w-[1600px]
          -translate-x-1/2 items-center justify-between
          rounded-[20px] sm:rounded-[26px] lg:rounded-[30px]
          border border-white/10
          bg-black/40
          px-4 py-3
          sm:px-6 sm:py-4
          lg:h-[92px] lg:px-9
          backdrop-blur-[18px]
          transition-opacity duration-[1800ms]
          overflow-hidden
          ${ready ? "opacity-100" : "opacity-0"}
        `}
      >
        {/* ── LEFT: Logo ── */}
        <div
          className={`flex items-center shrink-0 ${
            ready ? "animate-slideInLeft opacity-100" : "opacity-0"
          }`}
          style={{
            animationDelay: "2.1s",
          }}
        >
          <div
            className="flex items-center uppercase leading-none tracking-[-2px]"
            style={{
              fontFamily: "'Plus Jakarta Sans', sans-serif",
              fontWeight: 800,
            }}
          >
            {["R", "S", "D"].map((letter, i) => (
              <span
                key={letter}
                className={`${i > 0 ? "-ml-1 sm:-ml-2" : ""}`}
                style={{
                  fontSize: "clamp(24px,6vw,62px)",
                }}
              >
                {letter}
              </span>
            ))}
          </div>
        </div>

        {/* ── CENTER: Brand ── */}
        <div className="flex-1 text-center px-2 sm:px-4">
          <a
            href="#"
            className="
              block truncate uppercase text-white no-underline
              tracking-[3px]
              sm:tracking-[6px]
              lg:tracking-[10px]
            "
            style={{
              fontFamily: "'Tenor Sans', serif",
              fontSize: "clamp(10px,2vw,28px)",
            }}
          >
            Rakesh Sharma Design
          </a>
        </div>

        {/* ── RIGHT: Menu Button ── */}
        <div className="flex justify-end shrink-0">
          <button
            onClick={onMenuOpen}
            aria-label="Open Menu"
            className="
              group relative flex
              h-[46px] w-[46px]
              sm:h-[54px] sm:w-[54px]
              lg:h-[62px] lg:w-[62px]
              items-center justify-center
              overflow-hidden rounded-full
              border border-white/10
              bg-white/5
              transition-all duration-700
              hover:rotate-90 hover:scale-105
              active:scale-95
            "
          >
            <div className="relative z-10 flex flex-col gap-[4px] sm:gap-[5px]">
              <span className="block h-[1px] w-[18px] sm:w-[22px] bg-white" />
              <span className="block h-[1px] w-[18px] sm:w-[22px] bg-white" />
            </div>
          </button>
        </div>
      </header>

      {/* Local CSS */}
      <style jsx>{`
        @keyframes slideInLeft {
          from {
            opacity: 0;
            transform: translateX(-80px);
          }

          to {
            opacity: 1;
            transform: translateX(0);
          }
        }

        .animate-slideInLeft {
          animation: slideInLeft 2s cubic-bezier(0.19, 1, 0.22, 1) forwards;
        }
      `}</style>
    </>
  );
};

export default Header;
